var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"로터스 지사 연구소도 공격 받았답니다!","JPN":"ロータス支社の研究所も攻撃されたそうです！","ENG":"Even the Lotus branch came under attack!","TWN":"洛德斯分公司研究所也遭受攻擊！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"건설 중에 무너진 연구시설을 수습하는 비용에, 구조된 직원들의 입원비며…….","JPN":"建設中に倒壊した研究施設用の費用に、救助された社員の治療費や……","ENG":"I hear it cost a fortune cleaning up after all the destruction, as well as paying for the rescued employees' hospital bills…","TWN":"建設中倒塌的研究設施整理費，再加上受傷員工的醫療費……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"현지 태스크포스들까지 고용했는데 당했다던데?","JPN":"現地のタスクフォースカンパニーまで雇ったのにやられたんだってよ？","ENG":"I heard they hired local TASKFORCEs but that didn't do any good!","TWN":"我們還雇傭當地的特遣勢力，也都全軍覆沒嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"주가가 오늘만 30%가 넘게 빠졌대. 입사할 때 스톡 옵션 받았는데, 젠장…….","JPN":"株価が今日だけで30％以上下がったらしい。入社する時ストックオプションをもらったんだが、ちぇっ……","ENG":"Shares dropped over 30% in a single day. So much for the stock options I got when I joined this company…","TWN":"股價光是今天就已經掉30%，我進公司時還有拿到認股權，該死……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"범인이 관리국에서 수배 중인 S급 카운터라며? 어쩌다가 그런 인간이랑 척을 진 거래?","JPN":"犯人は管理局が指名手配中のS級カウンターだって？　なぜそんなやつに恨まれてるんだ？","ENG":"I hear the culprit's an S-Grade Counter wanted by the Administration. How does anyone manage to make an enemy out of someone like that?","TWN":"犯人是管理局通緝中的S級制裁者？怎麼會招惹到那種人物？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"빌어먹을! 수색대는 대체 뭘 한 거야!","JPN":"くそ！　捜索隊はいったい何をしてるんだ！","ENG":"Those bastards! What is the search team even doing?!","TWN":"該死！搜查隊都是幹什麼吃的！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"수색대 탓 하기 전에 재정 상태부터 신경 쓰지 그래? 10년을 공들인 회사가 며칠만에 먼지만 남게 생겼는데?","JPN":"捜索隊のせいにする前に財政状況を気にしたらどう？\\n10年もかけて育てた会社が、たったの数日で倒産寸前なんだけど。","ENG":"You'd better look after your financial situation if you've got the time to whine about the search team! 10 years of hard work is about to go kaput in a few days.","TWN":"有力氣罵搜查隊，要不要先關心下公司的財務？花10年的時間好不容易建立起來的公司，才幾天內就變成廢墟咧？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"네가 그 때 끝장을 냈으면 이런 일도 안 생겼어!","JPN":"お前があの時ちゃんと始末しておけばこんなことにはならなかったんだよ！","ENG":"It wouldn't have come to this if you had finished her off right then and there!","TWN":"要是你當時有處理掉她的話，事情會變成這樣嗎！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"상부에 막대한 손해를 봤다는 사실이 알려지기라도 하면…….","JPN":"上層部に莫大な損害が発生した事実を知られたら……","ENG":"If leadership finds out how many losses I suffered…","TWN":"萬一上面發現受到這麼嚴重的損失……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"그야 버려지겠지.","JPN":"それは捨てられるでしょうね。","ENG":"They'll throw you out to rot on the street, of course.","TWN":"你會完蛋吧～"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"주둥이 닥쳐!!","JPN":"黙れ！！","ENG":"Hold your tongue!!","TWN":"給我閉嘴！！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_HATE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"자, 자기야. 너무 화내지 마. 무서워.","JPN":"ダ、ダーリン。そんなに怒らないで、怖いよ。","ENG":"B-babe… Please don't get so angry. You're frightening me.","TWN":"親…親愛的，你不要這麼生氣，人家會害怕。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_HATE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"……후우. 아니, 미안해. 조금 놀랐지.","JPN":"……ふぅ。驚かせてごめんね。","ENG":"…Oh. I'm sorry. I must have startled you.","TWN":"……呼，沒事，對不起，你嚇到了吧。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"진정하자. 윌버. 진정하는 거야. 저런 머저리들한테 일을 맡겼으니 당연한 결과야.","JPN":"落ち着け、ウィルバー。落ち着くんだ。あんな間抜けどもに仕事を任せたんだから当然の結果だ。","ENG":"Easy now, Wilbur. Easy. This is what I get for relying on those fools to get the job done.","TWN":"冷靜點，韋爾伯，冷靜。把事情交待給那些蠢蛋，這種結果也是可預期的。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"상황이 이렇게 된 이상 이제 유일한 해결책은 그 사채꾼을 잡아다 바치는 수밖에 없어.","JPN":"状況がこうなった以上、唯一の解決策はあの闇金野郎を捕まえて生贄にするしかない。","ENG":"Now that it's come to this, the only solution is to capture that loan shark and offer her as a tribute.","TWN":"事已至此，現在唯一的辦法，就是活捉那個放高利貸的進貢給上面的。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"그래. 학회의 지원만 있다면 이번에 입은 타격 정도는 얼마든지 복구할 수 있지.","JPN":"そうだ。学会の支援さえあれば、今回の損失なんていくらでも埋め合わせできる。","ENG":"Right. I'm sure with support from the Society, we can more than make up for our losses today.","TWN":"沒錯，只要有學會的資源，這次受到的損失，一定都可以救回來。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_PRIDE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"중요한 건 내가 그분들이 만족하실 만한 결과를 내놓는지야.","JPN":"大事なのは、あの方たちが満足いくような結果を出せるかどうかだ。","ENG":"The only important thing is to give them something that would please them.","TWN":"重點是我要拿出可以讓他們滿意的結果。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"확실히 걔 정도라면 <color=#ffd34c>호수</color>에 바치기 어울리지.","JPN":"確かにあの子なら<color=#ffd34c>湖</color>に捧げるのに相応しいわね。","ENG":"Sure, she'd certainly make an apt sacrifice for <color=#ffd34c>the Lake</color>.","TWN":"她的話，確實是很適合獻給<color=#ffd34c>湖水</color>。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"그렇지만 어떻게 잡게? 복수 운운할 땐 언제고 만나자마자 도망치기 바빴잖아?","JPN":"それで、どうやって捕まえるの？　復讐云々で出くわすやいなや、逃げるのに必死だったじゃない。","ENG":"But how would you go about catching her? After all that talk of revenge, you bailed out the moment you met her!","TWN":"但要怎麼捉到她？你口口聲聲說要報仇，結果看到人又嚇到拔腿就跑。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"흥. 그 무식한 사채꾼이 올 곳은 결국 여기로 정해져 있어.","JPN":"ふん。あの脳筋闇金野郎はどうせここに来るに決まっている。","ENG":"Hmph. That numbskull of a loan shark is bound to come here eventually.","TWN":"哼！那個放高利貸的一定會來這裡。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_PRIDE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"아티팩트 증폭 장치를 준비시켜 둬라. 본사에 들어오면 성대한 환영식을 열어 줘야지.","JPN":"アーティファクト増幅装置を用意しておけ。本社にきたら、盛大な歓迎会を開いてやらないと。","ENG":"Prepare the artifact augmenter. We'll give them a grand welcome once they set foot here.","TWN":"把人造神器增幅裝置給我準備好！等她一到總公司，我們就要盛大地歡迎她！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"자기야……. 나, 정말 여기 있어도 괜찮을까?","JPN":"ダーリン……私、本当にここにいてもいいの？","ENG":"Oh, babe… Do you think I really should be here?","TWN":"親愛的……我需要先離開嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"너무 걱정하지 마. 곧 전부 끝날 테니까.","JPN":"あまり心配するな。すぐに全部終わらせるから。","ENG":"Don't worry too much. This will all be over soon.","TWN":"別擔心，一切都快結束了。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"그렇지만 회사 분위기도 안 좋은데……. 부모님께서도 걱정하실 테고.","JPN":"でも会社の雰囲気も良くないし……両親も今頃心配しているかも……","ENG":"But with everything that's been going on here… I'm sure my parents are getting worried.","TWN":"可是公司的氣氛也不太好……而且我爸媽也會擔心…"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"걱정 말라고 했잖아. 지금 내 말을 못 믿는 거야?","JPN":"心配するなって言ったろ！　僕を信頼できないってのか！？","ENG":"I told you, you don't need worry about a thing. Are you saying you don't trust me?","TWN":"我不是叫你別擔心嗎！現在是不相信我嗎？！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"아, 아니. 그런 건 아니야. 미안해, 자기야.","JPN":"ち、違うの。そういうわけじゃないの。ごめんね、ダーリン。","ENG":"N-no. I mean, it's not like that. I'm sorry, babe.","TWN":"不…不是啦，我沒有不相信你，對不起親愛的。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"흐음…….","JPN":"ふうん……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"뭐, 교수님이 이미 보고했다는 얘기는 굳이 안 해 줘도 되려나?","JPN":"まあ、教授がすでに報告したって話はわざわざしなくてもいいかしら。","ENG":"Should I tell him that the Professor already briefed the leadership?… Nah.","TWN":"應該不用跟他說教授已經向上面報告了吧？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"네. 부학회장 레지나 맥크레디입니다.","JPN":"はい。副学会長のレジーナ・マクレディーです。","ENG":"Yes? This is Vice President Regina MacCready.","TWN":"喂，你好，我是學會副會長 蕾佳娜·麥克蕾蒂。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L43_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"학회 산하에 있는 셰나랍니다. 잘 부탁드려요.","JPN":"学会傘下のシェナです。よろしくお願いします。","ENG":"Hello, I'm Shena. I'm a member of the Society. How do you do.","TWN":"我是隸屬於學會的世娜，你好。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L44_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"반가워요. 다른 학회원들처럼 음침한 분이 아니라 다행이네요.","JPN":"ご挨拶できて嬉しいですわ。他の学会員のように陰湿な方ではなくて安心しました。","ENG":"Nice to meet you, Shena. Thank goodness you're not all dreary like the rest of the Society.","TWN":"你好，還好你不像其他學會成員那樣陰沉。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L45_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"후훗. 돌려 말씀하실 것 없이 학회 활동에 미진하다고 질타하셔도 돼요.","JPN":"フフッ。遠慮する必要はないので、学会活動に不十分だと叱ってもらっても構いませんよ。","ENG":"Heh. You don't have to beat around the bush. Just tell me I've been lazy about the Society's activities.","TWN":"呵呵～不需要跟我拐彎抹角，你大可直接責怪我沒把學會的事處理好。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아, 그런 건 아니에요. 저는 그저…….","JPN":"あ、いいえ。そんなわけではありません。私はただ……","ENG":"Oh, that's not what I meant. I just…","TWN":"沒那回事，我只是……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"잠시만요! 에델!","JPN":"少しお待ちを。エデル！","ENG":"Please excuse me for just a moment! Edel!","TWN":"你等我一下，艾瑟兒！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_MONSTER_MOVEMENT_11"},{"id":"L48_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"이 괴물들 제가 저택에 풀어 놓지 말라고 했잖아요! 중요한 서류를 다 먹어 버렸다고요!","JPN":"この化け物たちを邸宅の中に放さないでと言いましたでしょう！　大事な書類を食い尽くしてますわ！","ENG":"Didn't I tell you not to keep these monsters loose in the mansion?! They've eaten all the important documents!","TWN":"我不是叫你不要把這些怪物放到我家嗎！他們會把文件吃光光啦！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"후우……. 죄송합니다. 통신 중에 결례를 저지르다니 저도 아직 기품이 부족하네요.","JPN":"ふう……申し訳ございません。通信中に失礼いたしました。私もまだまだ未熟者ですわね。","ENG":"Whew... Apologies. I fear I still lack the due elegance to refrain from such discourteous behavior during a call.","TWN":"呼哈……抱歉，竟然在通話中失態，看來我還不夠穩呢。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"아뇨. 편하게 대해 주세요. 지금은 일개 학회원으로 취급하셔도 상관없답니다.","JPN":"いいえ、お気になさらず。今は一人の学会員として、気軽に接してください。","ENG":"Oh, that's all right. You don't have to be so formal with me. In fact, you can treat me like just another member of the Society, for now.","TWN":"沒關係，輕鬆就好，可以把我當成是一般的學會成員。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"크흠, 흠. 그렇게 말씀해 주신다면야…….","JPN":"コホン。そうおっしゃってくださるなら……","ENG":"Ahem, hmm. If you insist…","TWN":"咳咳，既然你這麼說……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"고고학부로부터 서신은 받았습니다. 학회가 후원하던 기업이 끔찍한 짓을 저지르고 있었더군요.","JPN":"考古学部からの書信は読ませていただきました。学会が後援していた企業が非道なことをやっていたようですね。","ENG":"I've received the letter from the archeological department. It seems a company under the Society's sponsorship has been committing a most atrocious offense.","TWN":"我收到考古學部的來信，說學會贊助的企業做出很可怕的事。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"하긴 충분히 그러고도 남을 곳이긴 하죠. 과거에는 몰상식한 짓만 골라서 했으니까요.","JPN":"まあ、あの企業のことですし、十分あり得ることでしょう。過去には非常識なことばかりしていたようですので。","ENG":"Then again, I suppose I can't say I'm surprised. They engaged in nothing but similar crass endeavors in the past.","TWN":"完全想像得到，畢竟他們之前專做些無知的事。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"부학회장님께서는 어떻게 생각하시나요? 방침이 정해졌을까요?","JPN":"副学会長はどう思いますか？　方針は決まりましたか？","ENG":"What's your take on this, Vice President? Do you think they've decided on the policy yet?","TWN":"副會長你意下如何呢？有什麼對策嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"네. 불법적인 임상 실험을 지원해 주고 싶은 마음은 손톱만큼도 없습니다.","JPN":"ええ、違法な臨床実験を支援するなんて微塵たりとも思っていませんわ。","ENG":"Yes. I don't have the faintest desire to continue sponsoring a company engaging in illicit clinical experiments.","TWN":"嗯，我完全沒有想要贊助非法臨床實驗的打算。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"하지만 대외적인 평판은 좋더군요.","JPN":"ですが、対外的な評判はよかったと聞きました。","ENG":"In contrast, however, they seem to enjoy a healthy reputation among the masses.","TWN":"但外面對他們的評價好像不錯。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"교차 검증을 위해 감찰관을 한 명 보냈으니……. 아니, 잠깐만.","JPN":"交差検証のために監察官を一人送らせていただきますので……いえ、少しお待ちを。","ENG":"I've thus dispatched someone from the inspector general office to cross-check their true nature… Hang on a second.","TWN":"所以我有派一位監察委員去查證……再等我一下。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L10_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"<color=#ffd34c>리벳! 왜 감찰관에 당신 이름이 적혀 있어?! 또 누굴 망신시키려고!</color>","JPN":"<color=#ffd34c>リベット！　なぜ監察官があなたになっているの？　また恥をかかせるつもりかしら！？</color>","ENG":"<color=#ffd34c>Rivet! Why are you listed as an inspector?! You'll embarrass us all again!</color>","TWN":"<color=#ffd34c>里維！監察委員的欄位上，為什麼是寫你的名字？！你又想害死誰啦！</color>"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"<color=#ffd34c>……세상에. 그새 짐싸고 출발해 버렸네.</color>","JPN":"<color=#ffd34c>……そんな。もう出発してしまったの？</color>","ENG":"<color=#ffd34c>…Oh my. She took off, just like that.</color>","TWN":"<color=#ffd34c>……天啊，這麼快打包完行李出發了嗎？！</color>"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"크흠. 리벳이라는 용병을 보냈습니다. 이상한 짓 저지르지 않게 잘 감시하세요.","JPN":"コホン。リベットという傭兵を送りましたわ。変なことをやらかさないように、しっかり監視してください。","ENG":"Ahem… I've dispatched a mercenary named Rivet. Please keep an eye on her to make sure she doesn't do anything strange.","TWN":"咳咳，我派的是一位叫里維的傭兵，請幫我看好她，別讓她做出奇怪的事。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L15_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"뭔가 역할이 반대가 되었네요. 고생이 많으시겠어요.","JPN":"なんだか役割が逆になった気がしますが。そちらも大変ですね。","ENG":"It seems like the roles have been reversed. You sure got your hands full.","TWN":"怎麼角色好像有點反過來的感覺？會長很辛苦吧？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"맞아요! 그렇죠? 제가 이상한 게 아니라 학회 사람들이 전부 이상한 거예요!","JPN":"そうですの！　そう思いますわよね？\\n私がおかしいんじゃなくて、学会の人たちがみんなおかしいんですもの！","ENG":"I know, right? It's everyone else in this Society that's weird, not me!","TWN":"沒錯！你說是不是！怪的不是我，是其他的學會成員！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"어쩌면 당신이야말로 제가 학회에서 애타게 찾던 상식인일지도 모르겠네요.","JPN":"もしかしたら、あなたこそが私が学会で待ちわびていた常識人かもしれませんわ。","ENG":"Perhaps you're the sole reasonable person in the Society I've been searching for so desperately.","TWN":"或許你就是我在學會中，尋尋覓覓的那個有識之士！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"부디 사건이 마무리되는 대로 영지에 찾아와 주세요. 차 한 잔 마시면서 얘기를 나누고 싶네요.","JPN":"事件が一段落したら、ぜひ領地にお越しください。お茶を飲みながらお話させていただきたいですわ。","ENG":"Please stop by the estate as soon as your matter is settled. I'd love to chat with you over a cup of tea.","TWN":"事情處理完後，請你務必要來領地找我。我們可以喝杯茶慢慢聊。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"어머. 맥크레디 영지에 초대해 주신다면 저에게는 크나큰 영광이죠.","JPN":"あら、マクレディー領地に招待していただけるなんて大変光栄です。","ENG":"Oh, wow! It'd be an honor to be invited to the MacCready Estate.","TWN":"哇喔～竟然邀請我到麥克蕾蒂領地，我真是受寵若驚呢～"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그래요. 음악에 조예가 있으신 모양인데, 와서 흥겨운 곡도 연주해 주시면 좋겠어요.","JPN":"ぜひそうしましょう。音楽に造詣があるようですし、おすすめの曲を演奏していただきたいですわ。","ENG":"It would be my pleasure. It seems that you're also musically gifted. It'd be most splendid if you could play a song or two while you're here.","TWN":"別這麼說，感覺你對音樂方面也有些研究，到時也要請你演奏幾曲呢～"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L22_1","type":"dialog","speaker":"BOSS_HORIZON_NULL_NULL","text":{"KOREA":"경호실장님, 대표님께 급히 전해 드려야 할 일이 있습니다.","JPN":"室長、代表に大至急報告があります。","ENG":"Ma'am, we have an urgent message for the boss.","TWN":"護衛室長，我有急事要跟代表報告。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L25_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"나한테 말해. 지금 저기압이니까 대신 전해 줄게.","JPN":"私に話しなさい。彼は今ご機嫌斜めだから、代わりに伝えるわ。","ENG":"Just tell me. I'll pass it on for you since he's been super cranky lately.","TWN":"跟我說吧，代表現在心情不好，我再轉告他就好。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"BOSS_HORIZON_NULL_NULL","text":{"KOREA":"도시 경비대에 접수된 신고입니다. 그로니아 국경지대에서 샤레이드 방향으로 미사일이 발사되었다더군요.","JPN":"都市警備隊からの情報です。グロニア国境地帯でシャレード方向にミサイルが発射されたそうです。","ENG":"This was just reported to the City Guard. A missile has been launched from the Gronian border towards Charade.","TWN":"我收到城市守衛的通報，有導彈從格羅尼亞國境發射至查雷德的方向。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"BOSS_HORIZON_NULL_NULL","text":{"KOREA":"격추에는 성공했는데, 파편 중 하나가 도심 외각에 떨어졌다고 합니다.","JPN":"撃墜には成功しましたが、破片の一つが郊外に落ちたそうです。","ENG":"They've managed to intercept the missile, but a fragment of the fuselage landed in a suburb.","TWN":"雖然有成功攔截擊落，但有一塊碎片掉到市中心外。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"……파편?","JPN":"……破片？","ENG":"…A fragment?","TWN":"……碎片？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"BOSS_HORIZON_NULL_NULL","text":{"KOREA":"네. 이게 추락 위치의 CCTV 영상인데…….","JPN":"はい、こちらが墜落位置にある監視カメラの映像ですが……","ENG":"Yes. This is the CCTV footage of the crash site…","TWN":"是的，這是擊落地點的CCTV影像……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"DEFENSECORPS_NPC_NULL_NULL","text":{"KOREA":"자자, 다들 물러서세요! 이 도로는 지금 통행금지 상태입니다!","JPN":"全員下がってください！　この道路は現在通行止めです！","ENG":"Stand back, everyone! This road is currently off limits!","TWN":"請離開！這條路現在禁止通行！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"DEFENSECORPS_NPC_NULL_NULL","text":{"KOREA":"지금 도시 관리국이 파견한 태스크포스가 오고 있습니다! 17번 도로로 우회하세요!","JPN":"現在、都市管理局が派遣したタスクフォースカンパニーが来ています！　17番道路に迂回してください！","ENG":"A TASKFORCE dispatched by City Management is on its way now! Please take a detour to Road 17!","TWN":"城市管理局派出的特遣勢力正在來的路上！請轉向第17大道！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"착지 확인. 샤레이드 진입에 성공했습니다.","JPN":"着地確認。シャレード進入に成功しました。","ENG":"Landing confirmed. Charade infiltrated successfully.","TWN":"確認著地，成功進入查雷德。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L36_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"성공적으로 검문을 통과했군요. 승차감은 좋지 않습니다만.","JPN":"検問通過に成功しました。乗り心地はよろしくないですが。","ENG":"Looks like I've cleared the checkpoint. I can't say it was a smooth ride, though.","TWN":"成功通過盤查，但搭乘體驗不太好。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"네. 이자율은 연 2.5%. 친절과 정성으로 모시는 호라이즌 파이낸스입니다.","JPN":"お電話ありがとうございます。利子率は年率2.5％。\\n誠実に、親切に、真心を込めておもてなしするホライズン・ファイナンスです。","ENG":"Thank you for calling Horizon Finance. Our annual interest rate is only 2.5%. At Horizon Finance, the customer comes first.","TWN":"喂，你好，年利率2.5%，竭誠為您服務的地平線金融。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L39_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"샤레이드에 왔다더군, 호라이즌.","JPN":"シャレードに来ているらしいな、ホライズン。","ENG":"I heard you're in Charade, Horizon.","TWN":"地平線，我聽說你到查雷德了。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L42_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"윌버. 먼저 안부 전화도 하다니 장족의 변화군요.","JPN":"ウィルバー。先に電話をかけてくれるとは、驚くべき成長ですね。","ENG":"Wilbur. How nice of you to call first.","TWN":"韋爾伯，你竟然還會先打電話問好，這是很棒的改變。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"늦게라도 자진해서 채무를 변제할 생각이 들었습니까?","JPN":"ようやく自主的に債務を返済する気になったのですか？","ENG":"Have you finally decided to yield and repay your debt?","TWN":"你終於願意清償債務了嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"엉터리 같은 핑계는 집어치워라, 고철 사채꾼.","JPN":"でたらめな言いがかりはやめろ、鉄くずめ。","ENG":"Save your poppycock excuses, you piece of junk.","TWN":"廢鐵高利貸，少跟我廢話那麼多！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"그래, 내 얼굴에 먹칠을 하러 관리국 직할 도시까지 기어 들어왔단 말이지.","JPN":"僕の顔に泥を塗るために管理局直轄都市まで来やがったんだな。","ENG":"So you crawled all the way into an ADC just to defame me, huh.","TWN":"很好，你還特地跑到管理局的直轄市要來毀掉我，想害我臉上無光是嗎！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"저는 당신 상판대기에 관심이 없습니다. 윌버.","JPN":"私はあなたの顔には興味がありません、ウィルバー。","ENG":"I'm not interested in your paltry reputation, Wilbur.","TWN":"我對你的臉上有沒有光不是很在意，韋爾伯。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"웃기지 마라. 네가 왜 날 못 괴롭혀서 안달인지는 다 알고 있으니까.","JPN":"ふざけるな。貴様がなぜ僕にここまで執着しているのか、全部わかっているぞ。","ENG":"Don't be ridiculous. I know exactly why you're so hellbent on bullying me.","TWN":"笑死！我知道，你不弄我你就渾身不舒服對吧！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"방금도 말하지 않았습니까. 빚이나 갚으십시오.","JPN":"さっきも言ったはずです。いいから借金を返してください。","ENG":"Have I not made myself clear? I'm simply here to collect your debt.","TWN":"我剛剛不是有說嗎？請你還債。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"아니! 넌 사회적으로 성공한 내 모습이 부러워서 견딜 수 없는 거야!","JPN":"違う！　貴様は成功して社会的地位を得た僕が羨ましくてたまらないんだ！","ENG":"I don't think so! You just can't stand the sight of me becoming so successful!","TWN":"少來！是因為我在社會上有這麼好的成就，所以你羨慕忌妒恨！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"성공할 능력도 없고 그럴 의지도 없는 무식한 쓰레기들한테 기생하던 네가!","JPN":"成功する能力もなく、そんな意志もない無知なクズどもに寄生していた貴様が！","ENG":"After leeching off all those hopelessly incompetent and unmotivated scumbags…","TWN":"你原本依附著那些沒能力又胸無大志的垃圾！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_HATE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"그깟 돈 몇 푼 때문에 너한테 고개 숙이던 내가 성공했다는 소식을 들으니 질투가 날 만도 하지!","JPN":"わずかな金のために貴様に頭を下げていた僕が成功したと聞いたら、そりゃあ嫉妬するだろうな！","ENG":"You're now jealous to hear that I've outgrown my pathetic past with you and achieved such great success!","TWN":"聽到原本為了幾個錢向你低頭的我，現在這麼成功的消息，所以很忌妒對吧！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"그런데 아직도 모르겠나, 호라이즌? 너와 나는 이미 다른 세계에 살고 있다는 사실을?","JPN":"だがまだわからないのか、ホライズン？　貴様と僕はもう生きる世界が違うという事実を！","ENG":"You still don't get it, do you, Horizon? You and I are living in entirely different worlds.","TWN":"但是地平線你還搞不清楚嗎？我和你已經是不同世界的人！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_PRIDE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"너는 잔머리 굴려 남의 돈을 뜯어내려고 혈안이 된 사회의 기생충!","JPN":"貴様は小細工して他人の金を巻き上げようとする、金に目が眩んだ社会の寄生虫！","ENG":"You're just a parasite hellbent on ripping off poor fools with your schemes!","TWN":"你是拼命耍手段，要從別人身上榨取金錢的社會寄生蟲！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"그리고 나는 샤레이드의 유니콘으로 주목 받는 신흥 기업의 대표!","JPN":"そして僕はシャレードのユニコーンとして注目される新興企業の代表！","ENG":"Whereas I'm the CEO of Charade's most promising unicorn!","TWN":"而我則是查雷德最受矚目的新興企業代表！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"그런데 네가 내 인생에 참견한 시점에서 자기 주제를 한참 넘어 버렸어!","JPN":"身の程知らずの貴様が僕の人生に干渉した時点で、大きな過ちを犯したんだよ！","ENG":"You overstepped your boundaries the moment you decided to meddle in my life!","TWN":"但從你干預我的人生開始，你就不斷越界！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"네놈이 여기까지 올 수 있을 것 같아?! 내 털끝 하나 건드릴 수 있을 것 같냐고!!","JPN":"まさか貴様がここまで来れると思ってないよな！？　僕の髪の毛一本ですら触れられる自信があるのかよ！！","ENG":"Do you think a loser like you could ever get to where I am today?! You won't even reach the tip of my toes!","TWN":"你憑什麼來這裡？！你以為你能動我一根寒毛嗎！！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"개수작 작작 피우고 그만 꺼져! 네가 살던 쓰레기통 속에 다시 처박혀 있으란 말이다!","JPN":"ふざけた真似もいい加減にしろ！\\n貴様が住んでいたゴミ箱の中に大人しく引っ込んでろってことだ！","ENG":"Now shove your malarkey up your butt and get lost! Go crawl back into the trash can you came from!","TWN":"少在那邊給我胡說八道，給我滾！給我回到垃圾桶裡去生活！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"이제는 자기가 속물이란 사실도 숨기지 않는군요.","JPN":"もはや自分が俗物という事実すら隠さなくなりましたね。","ENG":"Now you won't even try to hide what a materialistic snob you are.","TWN":"你的黑暗面完全暴露出來了呢。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"제 목적은 처음부터 끝까지 하나였습니다. 윌버.","JPN":"私の目的は最初から最後まで一つのみです、ウィルバー。","ENG":"I've always had but one goal, Wilbur.","TWN":"韋爾伯，我的目的從頭至今都只有一個。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"빚이나 갚으십시오.","JPN":"借金を返済してください。","ENG":"Just pay your debt.","TWN":"就是請你還債。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"이, 이 빌어먹을 고물 로봇이 끝까지 억지를……!!","JPN":"こ、このくそロボットが最後まででたらめを……！！","ENG":"Y-you stubborn little piece of junk robot!!","TWN":"你…你這個破爛機器人！還在給我嘴硬……！！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"오래 통화하긴 어렵겠군요. 변제 상담을 원하면 직접 만나서 하시죠.","JPN":"長く通話するのは難しそうです。返済相談のご希望の場合は直接会ってからにしましょう。","ENG":"I'm afraid I can't stay on this call for too long. If you wish to discuss the terms of payment, we can do that in person.","TWN":"我無法通話太久，如果你想要債務協商，我可以直接去找你談。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"죄송합니다, 태스크포스 여러분. 오래 기다리셨습니까.","JPN":"すみません、タスクフォースカンパニーの皆様。お待たせしました。","ENG":"My apologies, TASKFORCE members. Thank you for your patience.","TWN":"特遣勢力的大家，抱歉讓你們久等了。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"관리국 지정 수배자, 호라이즌……. 인상착의는 자료와 일치하네요.","JPN":"管理局指名手配犯、ホライズン……見た目は資料と一致しますね。","ENG":"So you're Horizon, the fugitive wanted by the Administration… Your appearance does match the description.","TWN":"管理局的通緝犯 地平線……衣著長相和描述的一致。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"IRIE_CIVIL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"오, 오피셜 서포트의 소대장, 제나 버드입니다.","JPN":"オ、オフィシャルサポートの小隊長、ジーナ・バードです。","ENG":"I-I'm Zena Bird, commander of the Official Support Squad!","TWN":"我…我是官方支援小隊長 珍娜·布林德。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"IRIE_CIVIL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L22_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"아시겠지만, 샤레이드는 관리국 직할 도시예요. 무허가 출입은 엄격히 통제됩니다.","JPN":"ご存知だと思いますが、シャレードは管理局直轄都市です。無許可の出入りは厳格に制限されます。","ENG":"As you may know, Charade is an ADC. Unauthorized entry is strictly prohibited.","TWN":"你應該也知道，查雷德是管理局的直轄市，沒有出入許可是嚴格禁止進出的。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"IRIE_CIVIL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"IRIE_CIVIL_NULL_NULL","text":{"KOREA":"에이~ 왜 그래, 제나~","JPN":"え～どうしたの、ジ～ナ。","ENG":"Aw, come on Zena.","TWN":"哎呀～珍娜你幹嘛這樣～"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"IRIE_CIVIL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"IRIE_CIVIL_NULL_NULL","text":{"KOREA":"그렇게 긴장하고 있으면 전혀 무서워 보이지 않을걸~?","JPN":"そんなに緊張しちゃうと、相手が全然ビビらなくなるよ～？","ENG":"You won't look intimidating at all if you tense up like that!","TWN":"你緊張成這樣，看起來很沒有氣勢欸～"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"IRIE_CIVIL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"그, 그렇지만 상대는 엄청 흉악한 수배자잖아! 긴장하는 게 당연하지!","JPN":"で、でも相手はものすごく凶悪な指名手配犯だ！　緊張して当然だろ！","ENG":"B-but we're dealing with a violent, wanted felon! Of course I'm nervous!","TWN":"對…對方可是凶狠的通緝犯欸！會緊張是正常的吧！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"IRIE_CIVIL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"장애물이 아니라면 배제하지 않습니다. 비켜 주시죠.","JPN":"障害物でなければ排除はしません。退いてください。","ENG":"I will not engage if you do not hinder me. Please move out of my way.","TWN":"只要不當障礙物擋路，我是不會進行排除作業的。請讓開。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"저희도 순순히 길을 비켜 드리기는 어렵겠어요, 호라이즌 씨.","JPN":"私たちも素直に道を開けるわけにはいきません、ホライズンさん。","ENG":"I'm afraid we can't do that, Ms. Horizon.","TWN":"地平線小姐，我們可能無法乖乖地讓你過去喔。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L29_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"당신 이야기는 많이 들었어요. 하지만 여긴 관리국이 직할로 관리하는 요충지거든요.","JPN":"あなたの話は色々とお聞きしています。しかし、ここは管理局直轄の要衝地なんです。","ENG":"I've heard a lot about you. But this city is a strategic foothold managed directly by the Administration.","TWN":"你的事我也聽說不少，但這裡是管理局直轄管理的重鎮。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"여기서까지 소란을 피우시면 높으신 분들이 그렇게 달갑지 않아 하실 거예요.","JPN":"ここまで騒ぎ立てることは、上の方々が望まれていません。","ENG":"The top brass won't exactly appreciate it if you cause a scene here too.","TWN":"若你想在這裡滋事，那上面的人是不可能坐視不管的。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"당신들이 저를 가로막는 이유가 타당할지도 모릅니다.","JPN":"あなたたちが私を止める理由は妥当かもしれません。","ENG":"Perhaps you have a valid reason to stand in my way.","TWN":"或許你們有正當理由阻止我進去。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"하지만 저는 수금을 완수하기 위해 채무자가 신뢰하는 모든 방안을 돌파하기로 결론내렸습니다.","JPN":"しかし、私は集金を完遂するために、債務者が信頼するすべての方案を突破するという結論に至りました。","ENG":"But I am determined to collect what is owed to me. To do that, I will not hesitate to eradicate any obstacles the debtor may count on.","TWN":"　　"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"휴먼들이 느끼는 공포는 복장의 화려함이 아니라, 위력의 우열에서 비롯되니까요.","JPN":"ヒューマンたちが感じる恐怖は服装の下品さではなく、力の優劣から来ます。","ENG":"After all, humans fear superior might more than threateningly vulgar attire.","TWN":"會讓人類感到恐懼的，不在於穿什麼樣的衣服，而是在於對方的威力強弱。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그러니 그 자가 병력 뒤에 숨어도, 분석 불가능한 기술을 사용해도, 정치적인 논리를 이용해도 관계없습니다.","JPN":"ですから、その者が兵力の後ろに隠れても、\\n分析不可の技術を使っても、政治的な論理を駆使しても関係ありません。","ENG":"So it does not make a difference whether he hides behind hired muscle, employs skills impossible to analyze, or appeals with political reasoning.","TWN":"因此，無論他是要躲在兵力後，或是使用無法分析的技術，或是動用政治上的資源，都無所謂"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"저는 단지 제 앞에서 숨을 곳은 어디에도 없다는 사실을 증명할 뿐입니다.","JPN":"私はただ、私から隠れられる場所はどこにもないことを証明するのみです。","ENG":"I will simply demonstrate that there is nowhere he can hide from me.","TWN":"我只是要證明，在我面前是無處可躲的。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};